SELECT ?country (SAMPLE(?countryLabel) AS ?countryName) ?percentage ?lifeExpectancy
WHERE {
  VALUES ?region { wd:Q344 wd:Q5553505 }
  ?country wdt:P361 ?region .
  ?country wdt:P143 wd:Q3621403 .
  ?country p:P143 ?statement .
  ?statement ps:P143 wd:Q3621403 ;
            pq:P2433 ?percentage .
  ?country wdt:P1331 ?lifeExpectancy .
  OPTIONAL {
    ?country rdfs:label ?countryLabel .
    FILTER (lang(?countryLabel) = "en")
  }
}
GROUP BY ?country ?percentage ?lifeExpectancy
ORDER BY ?lifeExpectancy

